head.script:
// 전역변수
scwin.sDate = WebSquare.date.getCurrentServerDate();
scwin.strFromDate = scwin.sDate.substring(0, 6) + "01";
scwin.strToDate = scwin.sDate;

scwin.params       = $c.win.getParent();
scwin.sView        = (scwin.params.sView == null) ? "" : scwin.params.sView;
scwin.strDate      = (scwin.params.strDate == null) ? scwin.sDate : scwin.params.strDate; // ""으로 수정 필요
scwin.strLobran    = (scwin.params.strLobran == null) ? "" : scwin.params.strLobran;
scwin.acctDeptCd   = (scwin.params.acctDeptCd == null) ? "" : scwin.params.acctDeptCd;

scwin.dateStr = scwin.sDate

scwin.login             = $c.data.getMemInfo();
scwin.privAdmin         = scwin.login.privAdmin;
scwin.vUserHomeClsCd    = scwin.login.userHomeClsCd;
scwin.vLoginCoCd        = scwin.login.coCd;
scwin.vLoginCoClsCd     = scwin.login.coClsCd;
scwin.isChecked         = true;

// 내부 처리용
scwin.g_StdDt           = "";   // 기준일자 (조회 후 갱신)
scwin.isSubCompany      = false; // 자회사 여부 플래그

  //-------------------------------------------------------------------------
  // 각 Argument에 따른 PopUp을 호출 한다.
  // 1:조회->거래처 , 2:조회->귀속부서
  // code변수는 각 항목별 검색요청 값이다.
  //-------------------------------------------------------------------------
scwin.f_openPopUp = async function(orgObjCd, orgObjNm, select_code, flag) {

	// POPUP 돋보기 클릭시는 모든값을 조회 할 수 있도록 한다. flag:ALL일 경우는 돋보기 클릭한것임.
	// 넘어온 OBJ가 EMEdit인지 TextBox인지 구분한다.
	// flag:SKIP일경우는 Tag에 대한 속성 검사를 하지 않는다.
	if ( flag != "SKIP") {
        cd = orgObjCd.getValue();
        nm = orgObjNm.getValue();
	} else {
		cd = orgObjCd;
		nm = "";
	}


  	switch (select_code) {
		// 조회조건용 거래처 PopUp 호출
		 case '1' :
			param    = ",,,"+ed_coCd.getValue();		 
	  		udc_clntList.cfCommonPopUp(scwin.udc_clntList_callBackFunc, cd,nm,"T",null,null,null,null,param,null,null,null,null); // 거래처	  		
		 	break;
		// 조회조건용 청구부서 PopUp 호출
		 case '2' :
			param    = ","+ ed_coCd.getValue()+","+scwin.txtCoClsCd; 		 
			udc_acctDeptCdInfo6.cfCommonPopUp(scwin.udc_acctDeptCdInfo6_callBackFunc, cd, nm,"T",null,null,null,null,param,null,null,null,null,null,null,null,null); // 귀속부서							
		 	break;
	    // 조회조건용 수금부서 PopUp 호출
		 case '3' :
		     udc_empInfo.cfCommonPopUp(scwin.udc_empInfo_callBackFunc, cd, nm,"T",null,null,null,null,null,null,null,null,null,null,'F',"사원,사원코드,사원명"); // 관리부서		     
		 	break;
		 case '4' :
	 	    udc_crnInfo.cfCommonPopUp(scwin.udc_crnInfo_callBackFunc, cd,nm,"T",null,null,null,null,null,null,null,null,null); //사업자번호
	        break;
		 default :
		 	await $c.win.alert("잘못된 Function호출 입니다. 관리자에게 문의하시기 바랍니다.");
		 	break;
	}
  }

//-------------------------------------------------------------------------
// 팝업결과
//-------------------------------------------------------------------------
scwin.udc_clntList_callBackFunc = function(rtnList) {
    if (rtnList != null ) {
        if ( rtnList[0] == "N/A" ) return ;
        ed_sclntNo.setValue(rtnList[0]);	// 코드값
        ed_sclntNm.setValue(rtnList[1]);	// 코드명
        ed_sclntNo.options.hidVal = rtnList[0];	// HIDDEN 코드값
        ed_sclntNm.options.hidVal = rtnList[1];	// HIDDEN 코드명
    } else {
        ed_sclntNo.setValue("");
        ed_sclntNm.setValue("");
        ed_sclntNo.options.hidVal = "";
        ed_sclntNm.options.hidVal = "";
    }
};

scwin.udc_acctDeptCdInfo6_callBackFunc = function(rtnList) {
    if (rtnList != null ) {
        if ( rtnList[0] == "N/A" ) return ;
        ed_bilgAcctDeptCd.setValue(rtnList[0]);	// 코드값
        ed_bilgAcctDeptNm.setValue(rtnList[1]);	// 코드명
        ed_bilgAcctDeptCd.options.hidVal = rtnList[0];	// HIDDEN 코드값
        ed_bilgAcctDeptNm.options.hidVal = rtnList[1];	// HIDDEN 코드명
    } else {
        ed_bilgAcctDeptCd.setValue("");
        ed_bilgAcctDeptNm.setValue("");
        ed_bilgAcctDeptCd.options.hidVal = "";
        ed_bilgAcctDeptNm.options.hidVal = "";
    }
};

scwin.udc_empInfo_callBackFunc = function(rtnList) {
    if (rtnList != null ) {
        if ( rtnList[0] == "N/A" ) return ;
        ed_staffNo.setValue(rtnList[0]);	// 코드값
        ed_staffNm.setValue(rtnList[1]);	// 코드명
        ed_staffNo.options.hidVal = rtnList[0];	// HIDDEN 코드값
        ed_staffNm.options.hidVal = rtnList[1];	// HIDDEN 코드명
    } else {
        ed_staffNo.setValue("");
        ed_staffNm.setValue("");
        ed_staffNo.options.hidVal = "";
        ed_staffNm.options.hidVal = "";
    }
};

scwin.udc_crnInfo_callBackFunc = function(rtnList) {
    if (rtnList != null ) {
        if ( rtnList[0] == "N/A" ) return ;
        ed_crn.setValue(rtnList[0]);	// 코드값
        ed_crnNm.setValue(rtnList[1]);	// 코드명
        ed_crn.options.hidVal = rtnList[0];	// HIDDEN 코드값
        ed_crnNm.options.hidVal = rtnList[1];	// HIDDEN 코드명
    } else {
        ed_crn.setValue("");
        ed_crnNm.setValue("");
        ed_crn.options.hidVal = "";
        ed_crnNm.options.hidVal = "";
    }
};


//-------------------------------------------------------------------------
// PopUp창에서 사용되는 각 Cd,Nm에 대해서 POPUP표시 및 해당 값이 없을경우는 코드와 이름을 초기화 시킨다.
// flag값이 CD:코드변경이 없으면 POPUP안뛰움, NM:무조건 POPUP뛰움
//-------------------------------------------------------------------------
scwin.f_CheckPopUp = function(orgObjCd, orgObjNm, select_code, flag) {
    if ( flag == "CD") {
            orgObjNm.setValue("");
    } else {
            orgObjCd.setValue("");
    }

    if (orgObjCd.getValue().trim() != "" || flag == "NM") {
        if (orgObjNm.getValue().trim() != "" || flag == "CD") {
            orgObjCd.setValue(orgObjCd.getValue().trim());
            orgObjNm.setValue(orgObjNm.getValue().trim());
            scwin.f_openPopUp(orgObjCd, orgObjNm, select_code,"NO");
        }
    } else {
        orgObjNm.setValue("");
        orgObjCd.setValue("");
        orgObjCd.options.hidVal = "";
    }
}

//-------------------------------------------------------------------------
// 화면로딩시
//-------------------------------------------------------------------------
scwin.onpageload = function() {
    // grp_overDayAcctRecvFcrc.hide();
    grp_overDayAcctRecvFcrc.setStyle("display", "none")
    gr_overDayAcctRecvFcrc_excel.hide();
    $c.gus.cfDisableObjects([ica_currDt]);

    const codeOptions = [
        { grpCd : "FM120", compID : "gr_overDayAcctRecv:quitYn,gr_overDayAcctRecvFcrc:quitYn" },
        { grpCd : "FM050", compID : "acb_clntKnd" },
        { grpCd : "FM069", compID : "acb_overDayStandard" },
        { grpCd : "FM120", compID : "acb_quitYn" },
    ];

    $c.data.setCommonCode(codeOptions);
};

