//-------------------------------------------------------------------------
// 엑셀 파일 다운로드
//-------------------------------------------------------------------------
scwin.f_Export = async function () {
    const options = {
        fileName : "",
        sheetTitle : "",
        startRowIndex : 3,
        startColumnIndex  : 0,
        type : 1
    }

    if(acb_fcrcYn.getValue() == "1"){
        // if (ds_overDayAcctRecv.getRowCount() <= 0){
        //     await $c.win.alert(MSG_CM_WRN_002);
        //     return;
        // }

        if (await $c.win.confirm("Excel로 다운로드 하시겠습니까?")) {
            options.fileName = '초과일별채권현황조회.xlsx';
            options.sheetTitle = '초과일별채권현황';

            let infoArr = [{
                rowIndex : 0,             // 첫 번째 줄
                colIndex : 0,             // 첫 번째 칸부터
                colSpan : gr_overDayAcctRecv.getTotalCol(),   // 그리드 전체 너비만큼 병합
                rowSpan : 1,
                text : "초과일별채권현황",
                textAlign : "center",     //정렬
                fontSize : 18,
                drawBorder : false,        // 테두리
                color : "black",          // 글자색
                backgroundColor : "white" // 배경색
            }]

            await $c.data.downloadGridViewExcel(gr_overDayAcctRecv, options, infoArr);
        }

    }else if(acb_fcrcYn.getValue() == "2"){
        if (ds_overDayAcctRecvFcrc.getRowCount() <= 0){
            await $c.win.alert(MSG_CM_WRN_002);
            return;
        }

        if (await $c.win.confirm("Excel로 다운로드 하시겠습니까?")) {
            options.fileName = '초과일별채권현황조회_.xlsx';
            options.sheetTitle = '외화초과일별채권현황';

            let infoArr = [{
                rowIndex : 0,             // 첫 번째 줄
                colIndex : 0,             // 첫 번째 칸부터
                colSpan : gr_overDayAcctRecv.getTotalCol(),   // 그리드 전체 너비만큼 병합
                rowSpan : 1,
                text : "외화초과일별채권현황",
                textAlign : "center",     //정렬
                fontSize : 18,
                drawBorder : false,        // 테두리
                color : "black",          // 글자색
                backgroundColor : "white" // 배경색
            }]

            await $c.data.downloadGridViewExcel(gr_overDayAcctRecvFcrc, options, infoArr);
        }
    }
}


//-------------------------------------------------------------------------
// 원화 외화 select 변경시 이벤트
//-------------------------------------------------------------------------
scwin.acb_fcrcYn_onchange = function (info) {
    if (acb_fcrcYn.getValue() === "1"){
        grp_overDayAcctRecvFcrc.hide();
        gr_overDayAcctRecvFcrc_excel.hide();
        grp_overDayAcctRecv.show();
        grp_overDayAcctRecv_excel.show();
    }
    if (acb_fcrcYn.getValue() === "2"){
        grp_overDayAcctRecvFcrc.show();
        gr_overDayAcctRecvFcrc_excel.show();
        grp_overDayAcctRecv.hide();
        grp_overDayAcctRecv_excel.hide();

    }
};

//-------------------------------------------------------------------------
// script
//-------------------------------------------------------------------------
scwin.sbm_searchAcctRecv_submitdone = async function (e) {
    if (e.responseJSON.resultDataSet[0].Code < 0) return;
    let rowCnt1 = ds_overDayAcctRecv.getRowCount();
    let rowCnt2 = ds_overDayAcctRecvFcrc.getRowCount();

    if($c.gus.cfCheckCreateFlag() == true){
        $c.gus.cfTurnCreateFlag(false);
        }
    if (rowCnt1 == 0) {
        await $c.win.alert("조회된 데이터없음");
    }
    ds_overDayAcctRecv.sort("clntNm", 0);
    ds_overDayAcctRecvFcrc.sort("clntNm", 0);
    totalRows1.setValue(rowCnt1);
    totalRows2.setValue(rowCnt2);
};


scwin.acb_stdPoint_onviewchange = function (info) {
    if(acb_stdPoint.getValue() == "0") {
        ica_currDt.setValue("");
        $c.gus.cfDisableObjects([ica_currDt]);
    }else{
        ica_currDt.setValue(scwin.dateStr);
        $c.gus.cfEnableObjects([ica_currDt])
    }
};


